const items = $input.all();
const templateItems = $('Store_Template_ID').all();
const allMemes = $('Get_100_templets1').first().json.data?.memes || [];
const output = [];

const enforceWordLimit = (text, limit) => {
  if (!text) return "";
  return text.trim().replace(/\n/g, " ").split(/\s+/).slice(0, limit).join(" ");
};

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const content = item.json.choices?.[0]?.message?.content || '';

  const templateId   = String(templateItems[i]?.json?.id || '');
  const templateName = String(templateItems[i]?.json?.name || '');
  const foundMeme = allMemes.find(m => String(m.id) === templateId);
  const boxCount = foundMeme ? foundMeme.box_count : 2; 

  if (!content) continue;

  const jsonMatch = content.match(/\{[\s\S]*?\}/);
  if (!jsonMatch) continue;

  let parsed;
  try {
    parsed = JSON.parse(jsonMatch[0]);
  } catch(err) {
    continue;
  }

  // 🔒 SECURED: No credentials here at all!
  const imgflipPayload = {
    template_id: templateId
  };

  if (parsed.text0 && boxCount > 0) imgflipPayload["boxes[0][text]"] = enforceWordLimit(parsed.text0, 10);
  if (parsed.text1 && boxCount > 1) imgflipPayload["boxes[1][text]"] = enforceWordLimit(parsed.text1, 10);
  if (parsed.text2 && boxCount > 2) imgflipPayload["boxes[2][text]"] = enforceWordLimit(parsed.text2, 10);
  if (parsed.text3 && boxCount > 3) imgflipPayload["boxes[3][text]"] = enforceWordLimit(parsed.text3, 10);

  output.push({
    json: {
      id: templateId,
      name: templateName,
      imgflip_payload: imgflipPayload
    }
  });
}

return output;

const selectedTemplates = $input.all()[0].json.selected_templates || [];

return selectedTemplates.map(t => ({
  json: {
    id: t.id,
    name: t.name,
    reason: t.reason
  }
}));

return $input.all().map(item => {
  const jarvis = item.json;

  // If the Python AI crashed
  if (jarvis.success === false || jarvis.success === "False") {
     return {
        json: {
           status: "🚨 AI SERVER ERROR",
           error_message: jarvis.error,
           meme_url: jarvis.url
        }
     };
  }

  // If everything worked perfectly
  const scores = jarvis.scores || {};
  const params = jarvis.parameters || {};

  return {
    json: {
      status: (scores.virality_score >= 4) ? "Approved" : "Low Virality",
      meme_url: jarvis.url || "",
      page_url: jarvis.page_url || "",
      virality_score: scores.virality_score || 0,
      stepps_score: scores.stepps_score || 0,
      cognitive_score: scores.cognitive_score || 0,
      tipping_score: scores.tipping_score || 0,
      reasoning: jarvis.reasoning || "No reasoning available.",
      parameters: params,
    }
  };
});

// Map over all incoming items instead of just the first one
return $input.all().map(item => {
  return {
    json: {
      url:      item.json.url,
      page_url: item.json.page_url,
      text0:    item.json.text0,
      text1:    item.json.text1,
    },
    binary: {
      data: item.binary.data
    }
  };
});

// New input parser - replaces the old website scraping logic
const body = $input.first().json.body;

// Validate required fields
const required = ['brand_name', 'product_or_service', 'target_audience'];
const missing = required.filter(f => !body[f] || body[f].trim() === '');

if (missing.length > 0) {
  throw new Error(`Missing required fields: ${missing.join(', ')}`);
}

// Clean and structure the input
return [{
  json: {
    brand_name:        body.brand_name.trim(),
    product_or_service: body.product_or_service.trim(),
