    // Keep these for downstream nodes that reference them
    user_description:  `${body.brand_name} - ${body.product_or_service}`,
    timestamp:         new Date().toISOString(),
    campaign_id:       Math.random().toString(36).substring(2, 10).toUpperCase()
  }
}];

