const results = $input.first().json.result || [];

// Deduplicate by text
const seen = new Set();
const trends = [];
for (const r of results) {
  const text = r.payload.text;
  if (!seen.has(text)) {
    seen.add(text);
    trends.push(text);
  }
}

return [{
  json: {
    relevant_trends: trends,
    trends_string: trends.join(', ')
  }
}];

