const items = $input.all();
const results = [];

// Using a standard 'for' loop prevents the 'this' context error
for (let i = 0; i < items.length; i++) {
  const item = items[i];
  let base64String = "";

  // Check if binary data named 'data' actually exists for this item
  if (item.binary && item.binary.data) {
    // Fetch the file from n8n's disk using the current item's index (i)
    const buffer = await this.helpers.getBinaryDataBuffer(i, 'data');
    base64String = buffer.toString('base64');
  }

  // Push the original JSON plus our new real base64 string
  results.push({
    json: {
      ...item.json,
      image_base64: base64String
    }
  });
}

return results;
